                  <div className="space-y-4">
                    {homestaysAdmin.map((h) => (
                      <HomestayCard
                        key={h.homestay_id}
                        homestay={h}
                        isExpanded={expandedHomestay === h.homestay_id}
                        onToggle={() =>
                          setExpandedHomestay(
                            expandedHomestay === h.homestay_id ? null : h.homestay_id
                          )
                        }
                        onApprove={() => handleHomestayStatus(h.homestay_id, "approved")}
